const input = items[0]?.json ?? {};

function parseJsonObject(value, fallback, fieldName) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  try {
    const parsed = JSON.parse(value);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
  } catch (error) {
    throw new Error(`${fieldName} must be valid JSON object`);
  }
  throw new Error(`${fieldName} must be a JSON object`);
}

const lead = {
  email: String(input.email ?? '').trim().toLowerCase(),
  name: String(input.name ?? '').trim(),
  company: String(input.company ?? '').trim(),
  website: String(input.website ?? '').trim(),
  source: String(input.source ?? '').trim(),
  utm_campaign: String(input.utm_campaign ?? '').trim(),
  utm_medium: String(input.utm_medium ?? '').trim(),
  lead_source_id: String(input.lead_source_id ?? '').trim(),
};

const missing = [];
for (const field of ['email', 'company']) {
  if (!lead[field]) missing.push(field);
}
if (missing.length) throw new Error(`Missing required lead fields: ${missing.join(', ')}`);
if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(lead.email)) throw new Error('Lead email is not valid');

const domain = lead.email.split('@')[1].toLowerCase();
const freeEmailDomains = new Set(['gmail.com','outlook.com','hotmail.com','yahoo.com','icloud.com','proton.me','protonmail.com']);
const companyDomain = lead.website ? lead.website.replace(/^https?:\/\//,'').replace(/^www\./,'').split('/')[0].toLowerCase() : domain;

const simulateSourceStatus = parseJsonObject(input.simulate_source_status, {}, 'simulate_source_status');
const simulateActionFailures = parseJsonObject(input.simulate_action_failures, {}, 'simulate_action_failures');

const config = {
  min_score_for_sales_alert: Number(input.min_score_for_sales_alert ?? 60),
  enterprise_score_threshold: Number(input.enterprise_score_threshold ?? 85),
  mid_market_score_threshold: Number(input.mid_market_score_threshold ?? 60),
  scoring_version: 'sales-fit-v1',
  retry_policy: {
    max_attempts: 3,
    backoff: 'exponential',
    retry_on: ['429', '408', '5xx', 'network_timeout'],
  },
  llm_policy: {
    enabled: String(input.llm_enabled ?? 'true') !== 'false',
    endpoint: String(input.llm_endpoint ?? 'http://localhost:5001/completions'),
    parameter: 'prompt',
    purpose: 'qualification wording only; deterministic score and route remain authoritative',
    data_minimisation: ['company', 'website_domain', 'industry', 'employee_count_band', 'country', 'source', 'score_reasons'],
  },
  simulate_source_status: simulateSourceStatus,
  simulate_action_failures: simulateActionFailures,
};

if (Number.isNaN(config.min_score_for_sales_alert) || config.min_score_for_sales_alert < 0 || config.min_score_for_sales_alert > 100) {
  throw new Error('min_score_for_sales_alert must be between 0 and 100');
}

const runId = `sales-enrichment-${lead.email}-${Date.now()}`;
const idempotencyBase = `${lead.email}:${lead.company}:${config.scoring_version}`;

return [{
  json: {
    lead,
    control: {
      run_id: runId,
      checked_at: new Date().toISOString(),
      email_domain: domain,
      company_domain: companyDomain,
      is_free_email_domain: freeEmailDomains.has(domain),
      idempotency_keys: {
        crm_upsert: `${idempotencyBase}:crm-upsert`,
        sales_notification: `${idempotencyBase}:sales-notification`,
        enrichment_log: `${idempotencyBase}:enrichment-log`,
      },
    },
    config,
  },
}];

const source = items[0]?.json ?? {};
const status = source.config?.simulate_source_status?.company ?? 'success';
const startedAt = new Date().toISOString();

function makeResult(status, data, warning) {
  return [{ json: { ...source, company_enrichment_result: { source: 'company_data', status, checked_at: startedAt, completed_at: new Date().toISOString(), source_timestamp: new Date().toISOString(), retry_policy: source.config.retry_policy, data, warning } } }];
}

try {
  if (status === 'failed') throw new Error('Simulated company enrichment provider failure');
  if (status === 'empty') return makeResult('empty', {}, 'Company provider returned no matching company record');
  const data = {
    legal_name: source.lead.company,
    employee_count: 350,
    employee_count_band: '201-500',
    industry: 'SaaS',
    country: 'US',
    annual_revenue_band: '10m-50m',
    funding_stage: 'Series B',
  };
  if (status === 'partial') {
    delete data.annual_revenue_band;
    return makeResult('partial', data, 'Company enrichment missing revenue band');
  }
  return makeResult('success', data);
} catch (error) {
  return makeResult('failed', {}, error.message);
}

const source = items[0]?.json ?? {};
const status = source.config?.simulate_source_status?.tech_stack ?? 'success';
const startedAt = new Date().toISOString();

function makeResult(status, data, warning) {
  return [{ json: { ...source, tech_stack_result: { source: 'tech_stack', status, checked_at: startedAt, completed_at: new Date().toISOString(), source_timestamp: new Date().toISOString(), retry_policy: source.config.retry_policy, data, warning } } }];
}

try {
  if (status === 'failed') throw new Error('Simulated tech-stack enrichment failure');
  if (status === 'empty') return makeResult('empty', { technologies: [] }, 'No technologies detected for domain');
  const data = { technologies: ['AWS', 'PostgreSQL', 'HubSpot', 'Segment'], has_crm: true, has_cloud_stack: true, has_data_stack: true };
  if (status === 'partial') {
    data.technologies = ['AWS', 'HubSpot'];
    return makeResult('partial', data, 'Only partial technology fingerprint available');
  }
  return makeResult('success', data);
} catch (error) {
  return makeResult('failed', { technologies: [] }, error.message);
}

const source = items[0]?.json ?? {};
const status = source.config?.simulate_source_status?.intent ?? 'success';
const startedAt = new Date().toISOString();

function makeResult(status, data, warning) {
  return [{ json: { ...source, intent_signal_result: { source: 'behavioural_intent', status, checked_at: startedAt, completed_at: new Date().toISOString(), source_timestamp: new Date().toISOString(), retry_policy: source.config.retry_policy, data, warning } } }];
}

try {
  if (status === 'failed') throw new Error('Simulated product/marketing intent source failure');
  if (status === 'empty') return makeResult('empty', {}, 'No behavioural intent events found');
  const data = {
    source_quality: source.lead.source.toLowerCase().includes('ebook') ? 'medium' : 'standard',
    page_views_7d: 9,
    pricing_page_views_7d: 2,
    demo_requested: false,
    content_downloaded: true,
    campaign: source.lead.utm_campaign,
  };
  if (status === 'partial') {
    delete data.pricing_page_views_7d;
    return makeResult('partial', data, 'Intent data missing pricing-page events');
  }
  return makeResult('success', data);
} catch (error) {
  return makeResult('failed', {}, error.message);
}

const source = items[0]?.json ?? {};
const status = source.config?.simulate_source_status?.crm_history ?? 'success';
const startedAt = new Date().toISOString();

function makeResult(status, data, warning) {
  return [{ json: { ...source, crm_history_result: { source: 'crm_history', status, checked_at: startedAt, completed_at: new Date().toISOString(), source_timestamp: new Date().toISOString(), retry_policy: source.config.retry_policy, data, warning } } }];
}

try {
  if (status === 'failed') throw new Error('Simulated CRM history lookup failure');
  if (status === 'empty') return makeResult('empty', { existing_account: false }, 'No existing CRM account or contact found');
  const data = {
    existing_account: true,
    account_id: 'acct_acme',
    lifecycle_stage: 'prospect',
    open_opportunities: 0,
    last_contacted_at: '2026-06-28',
    account_owner: 'midmarket@yourcompany.com',
  };
  if (status === 'partial') {
    delete data.last_contacted_at;
    return makeResult('partial', data, 'CRM account found but last-contact timestamp missing');
  }
  return makeResult('success', data);
} catch (error) {
  return makeResult('failed', {}, error.message);
}

const source = items[0]?.json ?? {};
const sourceResults = {
  company_data: source.company_enrichment_result,
  tech_stack: source.tech_stack_result,
  behavioural_intent: source.intent_signal_result,
  crm_history: source.crm_history_result,
};

const warnings = [];
const failed_sources = [];
for (const [key, result] of Object.entries(sourceResults)) {
  if (!result) {
    warnings.push(`${key}: missing source result`);
    failed_sources.push(key);
    continue;
  }
  if (['failed', 'partial', 'empty'].includes(result.status)) {
    warnings.push(`${key}: ${result.status}${result.warning ? ` - ${result.warning}` : ''}`);
  }
  if (result.status === 'failed') failed_sources.push(key);
}

const company = sourceResults.company_data?.data ?? {};
const tech = sourceResults.tech_stack?.data ?? {};
const intent = sourceResults.behavioural_intent?.data ?? {};
const crm = sourceResults.crm_history?.data ?? {};

const enriched_lead = {
  ...source.lead,
  enrichment: {
    legal_name: company.legal_name ?? source.lead.company,
    employee_count: company.employee_count,
    employee_count_band: company.employee_count_band,
    industry: company.industry,
    country: company.country,
    annual_revenue_band: company.annual_revenue_band,
    funding_stage: company.funding_stage,
    tech_stack: tech.technologies ?? [],
    has_crm: Boolean(tech.has_crm),
    has_cloud_stack: Boolean(tech.has_cloud_stack),
    has_data_stack: Boolean(tech.has_data_stack),
    intent,
    crm_history: crm,
  },
};

return [{ json: { ...source, source_results: sourceResults, source_warnings: warnings, failed_sources, enriched_lead } }];

const source = items[0]?.json ?? {};
const alerts = [];
for (const [key, result] of Object.entries(source.source_results ?? {})) {
  if (!result) continue;
  if (['failed', 'partial', 'empty'].includes(result.status)) {
    alerts.push({
      alert_type: 'sales_enrichment_source_degraded',
      source: key,
      status: result.status,
      warning: result.warning,
      checked_at: result.checked_at,
      recommended_action: 'Check enrichment credentials, provider availability, rate limits and payload mapping.',
    });
  }
}
return [{ json: { ...source, operations_alerts: alerts } }];

const source = items[0]?.json ?? {};
const lead = source.enriched_lead;
const e = lead.enrichment ?? {};
const reasons = [];
let score = 0;

const employeeCount = Number(e.employee_count ?? 0);
if (employeeCount >= 1000) { score += 35; reasons.push('Large enterprise employee count'); }
else if (employeeCount >= 200) { score += 28; reasons.push('Mid-market employee count'); }
else if (employeeCount >= 50) { score += 18; reasons.push('Commercial employee count'); }
else { score += 6; reasons.push('Small company size'); }

if (['SaaS','Financial Services','Technology'].includes(e.industry)) { score += 18; reasons.push(`Industry fit: ${e.industry}`); }
if (['US','GB','CA','AU','IE'].includes(e.country)) { score += 10; reasons.push(`Supported sales region: ${e.country}`); }
if ((e.tech_stack ?? []).includes('HubSpot') || e.has_crm) { score += 8; reasons.push('CRM or revenue tooling detected'); }
if (e.has_cloud_stack) { score += 7; reasons.push('Modern cloud stack detected'); }
if (e.intent?.pricing_page_views_7d >= 2) { score += 12; reasons.push('Recent pricing-page activity'); }
if (e.intent?.content_downloaded) { score += 5; reasons.push('Content engagement present'); }
if (e.crm_history?.existing_account) { score += 6; reasons.push('Existing CRM account context available'); }
if (source.control?.is_free_email_domain) { score -= 12; reasons.push('Free email domain reduces confidence'); }
if ((source.failed_sources ?? []).length) { score -= Math.min(10, source.failed_sources.length * 4); reasons.push('Score confidence reduced by failed enrichment source'); }

score = Math.max(0, Math.min(100, score));
let segment = 'self-serve';
let route = 'self_serve_nurture';
if (score >= source.config.enterprise_score_threshold || employeeCount >= 1000) { segment = 'enterprise'; route = 'enterprise_sales'; }
else if (score >= source.config.mid_market_score_threshold) { segment = 'mid-market'; route = 'mid_market_sales'; }

const confidence = (source.failed_sources ?? []).length ? 'medium' : (source.source_warnings?.length ? 'medium' : 'high');
const should_notify_sales = score >= source.config.min_score_for_sales_alert;

return [{ json: { ...source, scored_lead: { ...lead, score, segment, route, score_reasons: reasons, score_confidence: confidence, should_notify_sales, scoring_version: source.config.scoring_version } } }];

const source = items[0]?.json ?? {};
const lead = source.scored_lead;

if (!lead) {
  throw new Error('LLM qualification prompt expected scored_lead context');
}

const e = lead.enrichment ?? {};

const promptPayload = {
  company: lead.company,
  website_domain: source.control?.company_domain,
  industry: e.industry,
  employee_count_band: e.employee_count_band,
  country: e.country,
  source: lead.source,
  score: lead.score,
  segment: lead.segment,
  route: lead.route,
  score_reasons: lead.score_reasons,
  source_warnings: source.source_warnings,
};

const prompt = [
  'Write a concise B2B sales qualification note.',
  'Use only the provided account-level data. Do not invent facts.',
  'The deterministic score, segment and route are authoritative.',
  'Return only the note. Do not include JSON. Do not include a stop token.',
  'Use exactly this structure:',
  '## Account summary',
  'One sentence, maximum 35 words.',
  '',
  '## Qualification notes',
  '- Maximum 3 bullets.',
  '- Each bullet must be under 18 words.',
  '',
  'Total response limit: 100 words.',
  '',
  'Account data:',
  JSON.stringify(promptPayload, null, 2),
].join(String.fromCharCode(10));

return [{
  json: {
    ...source,
    llm_qualification_request: {
      enabled: source.config.llm_policy.enabled,
      endpoint: source.config.llm_policy.endpoint,
      body: {
        prompt,
        alias: 'general',
        n_predict: 120,
        max_tokens: 120,
        temperature: 0.1,
        top_p: 0.85,
      },
      data_policy: source.config.llm_policy,
      prompt_payload: promptPayload,
      response_contract: {
        max_words: 100,
        required_sections: ['Account summary', 'Qualification notes'],
      },
    },
  },
}];

const response = items[0]?.json ?? {};

function readOriginalContext() {
  const candidates = [];

  try {
    candidates.push($('Prepare Optional LLM Qualification Prompt').first().json);
  } catch (error) {}

  try {
    candidates.push($items('Prepare Optional LLM Qualification Prompt', 0, 0)?.[0]?.json);
  } catch (error) {}

  for (const candidate of candidates) {
    if (candidate && typeof candidate === 'object' && candidate.control && candidate.scored_lead) {
      return candidate;
    }
  }

  return {};
}

function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return '';
}

function deterministicSummary(original, reason) {
  const lead = original.scored_lead ?? original.enriched_lead ?? original.lead ?? {};
  const reasons = Array.isArray(lead.score_reasons) ? lead.score_reasons.slice(0, 3) : [];
  const company = lead.company ?? 'This lead';
  const route = lead.route ?? 'sales review';
  const score = lead.score ?? 'n/a';

  const summary = [
    '## Account summary',
    `${company} is routed to ${route} with a deterministic score of ${score}.`,
    '',
    '## Qualification notes',
    ...(reasons.length ? reasons.map(item => `- ${item}`) : ['- Deterministic scoring context was used because LLM output was unavailable.']),
  ].join(String.fromCharCode(10));

  return {
    ...original,
    llm_response_metadata: response,
    llm_summary: summary,
    qualification_mode: 'deterministic_fallback',
    llm_failure_alert: {
      alert_type: 'sales_qualification_llm_empty_or_invalid',
      message: reason,
    },
  };
}

const original = readOriginalContext();

let content = firstString(
  response.response,
  response.content,
  response.text,
  response.output,
  response.generated_text,
  response.message?.content,
  response.choices?.[0]?.message?.content,
  response.choices?.[0]?.text,
  response.data?.content,
  response.data?.text,
  response.data?.output,
  response.data?.choices?.[0]?.message?.content,
  response.data?.choices?.[0]?.text
);

if (!content && Array.isArray(response.output)) {
  content = response.output
    .map(part => typeof part === 'string' ? part : part?.content || part?.text || '')
    .filter(Boolean)
    .join(String.fromCharCode(10))
    .trim();
}

content = content
  .replace(/END_QUALIFICATION[\s\S]*$/i, '')
  .trim();

if (!original.control || !original.scored_lead) {
  throw new Error('LLM extraction could not recover original scored lead context');
}

if (!content) {
  const availableKeys = Object.keys(response).sort().join(', ');
  return [{ json: deterministicSummary(original, `LLM returned empty content. Available top-level fields: ${availableKeys}`) }];
}

if (content.length > 2500) {
  return [{ json: deterministicSummary(original, 'LLM qualification response exceeded safe length') }];
}

return [{
  json: {
    ...original,
    llm_response_metadata: response,
    llm_summary: content,
    qualification_mode: 'llm',
  },
}];

const source = items[0]?.json ?? {};

function readOriginalContext() {
  const candidates = [source];

  try {
    candidates.push($('Prepare Optional LLM Qualification Prompt').first().json);
  } catch (error) {}

  try {
    candidates.push($items('Prepare Optional LLM Qualification Prompt', 0, 0)?.[0]?.json);
  } catch (error) {}

  for (const candidate of candidates) {
    if (candidate && typeof candidate === 'object' && candidate.control && candidate.scored_lead) {
      return candidate;
    }
  }

  return source;
}

const original = readOriginalContext();
const lead = original.scored_lead ?? original.enriched_lead ?? original.lead ?? {};
const reasons = lead.score_reasons ?? [];

const summary = [
  '## Account summary',
  `${lead.company ?? 'This lead'} is routed to ${lead.route ?? 'sales review'} with a score of ${lead.score ?? 'n/a'}.`,
  '',
  '## Qualification notes',
  ...(reasons.length
    ? reasons.map(reason => `- ${reason}`)
    : ['- Qualification reasons unavailable because deterministic scoring context was not available.']),
].join(String.fromCharCode(10));

return [{
  json: {
    ...original,
    llm_response_metadata: source,
    llm_summary: summary,
    qualification_mode: 'deterministic_fallback',
    llm_failure_alert: {
      alert_type: 'sales_qualification_llm_failed',
      message: source.error?.message || source.message || 'Local LLM qualification failed or returned an unexpected response shape',
    },
  },
}];

const source = items[0]?.json ?? {};
const lead = source.scored_lead ?? {};
const failures = source.config?.simulate_action_failures ?? {};

if (!source.control?.idempotency_keys || !source.scored_lead) {
  throw new Error('Expected enriched lead context was missing before action preparation. Check LLM qualification merge/context preservation path.');
}
const failed = Boolean(failures.crm_upsert);
const result = failed ? {
  action: 'crm_upsert',
  status: 'failed',
  idempotency_key: source.control.idempotency_keys.crm_upsert,
  error: 'Simulated CRM upsert failure',
  completed_at: new Date().toISOString(),
} : {
  action: 'crm_upsert',
  status: 'prepared',
  idempotency_key: source.control.idempotency_keys.crm_upsert,
  completed_at: new Date().toISOString(),
  payload: {
    email: lead.email,
    name: lead.name,
    company: lead.company,
    website: lead.website,
    score: lead.score,
    segment: lead.segment,
    route: lead.route,
    score_confidence: lead.score_confidence,
    qualification_summary: source.llm_summary,
    source_warnings: source.source_warnings,
  },
  note: 'Replace this payload with HubSpot/Salesforce/Pipedrive/CRM upsert node.',
};
return [{ json: { ...source, crm_upsert_result: result } }];

const source = items[0]?.json ?? {};
const lead = source.scored_lead ?? {};
const failures = source.config?.simulate_action_failures ?? {};
const shouldNotify = Boolean(lead.should_notify_sales);
let result;
if (!shouldNotify) {
  result = { action: 'sales_notification', status: 'skipped', reason: 'Score below sales alert threshold', idempotency_key: source.control.idempotency_keys.sales_notification };
} else if (failures.sales_notification) {
  result = { action: 'sales_notification', status: 'failed', error: 'Simulated sales notification failure', idempotency_key: source.control.idempotency_keys.sales_notification };
} else {
  const channel = lead.route === 'enterprise_sales' ? '#sales-enterprise' : lead.route === 'mid_market_sales' ? '#sales-mid-market' : '#sales-self-serve';
  const message = [
    `New ${lead.segment} lead: ${lead.company}`,
    `Score: ${lead.score} (${lead.score_confidence} confidence)`,
    `Route: ${lead.route}`,
    `Contact: ${lead.name || 'Unknown'} <${lead.email}>`,
    '',
    source.llm_summary || 'No qualification summary available.',
  ].join(String.fromCharCode(10));
  result = { action: 'sales_notification', status: 'prepared', idempotency_key: source.control.idempotency_keys.sales_notification, channel, message, note: 'Replace this payload with Slack, Teams or email delivery node.' };
}
return [{ json: { ...source, sales_notification_result: result } }];

const source = items[0]?.json ?? {};
const lead = source.scored_lead ?? {};
const result = {
  action: 'enrichment_log',
  status: 'prepared',
  idempotency_key: source.control.idempotency_keys.enrichment_log,
  logged_at: new Date().toISOString(),
  record: {
    lead_email: lead.email,
    company: lead.company,
    score: lead.score,
    segment: lead.segment,
    route: lead.route,
    source_results: source.source_results,
    source_warnings: source.source_warnings,
    qualification_mode: source.qualification_mode,
  },
  note: 'Replace this payload with database, warehouse, spreadsheet or CRM activity logging.',
};
return [{ json: { ...source, enrichment_log_result: result } }];

const source = items[0]?.json ?? {};
const actionResults = {
  crm_upsert: source.crm_upsert_result,
  sales_notification: source.sales_notification_result,
  enrichment_log: source.enrichment_log_result,
};
const failedActions = Object.entries(actionResults).filter(([, result]) => result?.status === 'failed').map(([key]) => key);
const preparedActions = Object.entries(actionResults).filter(([, result]) => result?.status === 'prepared').map(([key]) => key);
const overall_status = failedActions.length ? (preparedActions.length ? 'partial_success' : 'failed') : 'success';

const output = {
  ...source.scored_lead,
  llm_summary: source.llm_summary,
  qualification_mode: source.qualification_mode,
  source_warnings: source.source_warnings,
  operations_alerts: source.operations_alerts,
  action_results: actionResults,
  overall_status,
};

const audit_record = {
  audit_type: 'sales_pipeline_enrichment_result',
  logged_at: new Date().toISOString(),
  run_id: source.control.run_id,
  lead_email: source.lead.email,
  company: source.lead.company,
  score: source.scored_lead.score,
  segment: source.scored_lead.segment,
  route: source.scored_lead.route,
  score_reasons: source.scored_lead.score_reasons,
  source_results: source.source_results,
  source_warnings: source.source_warnings,
  operations_alerts: source.operations_alerts,
  action_results: actionResults,
  idempotency_keys: source.control.idempotency_keys,
  llm_policy: source.config.llm_policy,
  qualification_mode: source.qualification_mode,
};

return [{ json: { ...source, enriched_scored_lead: output, audit_record, overall_status } }];
